entryCriteria.formula:
OR(
(AND(
CONTAINS(CreatedBy.UserRole.Name,"Specialist Junior"),
OR(
((ISPICKVAL(CC_DailyRate__c ,"Regular") || ISPICKVAL(CC_DailyRate__c ,"Premium") || 
ISPICKVAL(CC_DailyRate__c ,"Competitive vehicle") )&& (CC_TotalRentalDaysProvidedByAgent__c + 
CC_TotalRentalDaysProvidedByDealer__c ) > 5) , ISPICKVAL(CC_DailyRate__c ,"Other (special circumstances)")
)
)
),
(AND(
CONTAINS(CreatedBy.UserRole.Name,"Specialist Senior"),
OR(
((ISPICKVAL(CC_DailyRate__c ,"Regular") || ISPICKVAL(CC_DailyRate__c ,"Premium") || 
ISPICKVAL(CC_DailyRate__c ,"Competitive vehicle") )&& (CC_TotalRentalDaysProvidedByAgent__c + 
CC_TotalRentalDaysProvidedByDealer__c ) > 10) , ISPICKVAL(CC_DailyRate__c ,"Other (special circumstances)")
)
)
),
(AND(
CONTAINS(CreatedBy.UserRole.Name,"Top Care Agent"),
OR(
((ISPICKVAL(CC_DailyRate__c ,"Regular") || ISPICKVAL(CC_DailyRate__c ,"Premium") || 
ISPICKVAL(CC_DailyRate__c ,"Competitive vehicle") )&& (CC_TotalRentalDaysProvidedByAgent__c + 
CC_TotalRentalDaysProvidedByDealer__c ) > 20) , ISPICKVAL(CC_DailyRate__c ,"Other (special circumstances)")
)
)
)
)
